struct SafeInt {
	ll val;
	int zero_cnt;

	SafeInt() : val(1), zero_cnt(0) {}
	SafeInt(ll val) : val(val), zero_cnt(0) {}

	void mul(ll x) {
		x %= mod;
		if (x == 0)zero_cnt++;
		else val = val * x % mod;
	}

	void div(ll x) {
		x %= mod;
		if (x == 0)zero_cnt--;
		else val = val * Math::inv(x, mod) % mod;
	}

	// 获取真实值
	ll get() const {
		if (zero_cnt > 0) return 0;
		return val;
	}
};

void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	var b = vector<int>(n); // mex 对应的节点
	fa(i, 1, n)cin >> a[i], b[a[i]] = i;

	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	var dp = vector<ll>(n + 1); // 以 u 为根的子树中，包含 u 的连通子图的数量
	var par = vector<int>(n + 1); // u 的父节点 par[u]
	var dfs = [&](var dfs, int now, int fa)->void {
		dp[now] = 1;
		par[now] = fa;
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
			dp[now] = dp[now] * (dp[to] + 1) % mod;
		}
		};
	int st = b[0];
	dfs(dfs, st, 0);

	var vis = vector<bool>(n + 1);
	ll ans = dp[st];
	SafeInt tot = dp[st];
	vis[st] = 1;
	fa(i, 1, n - 1) {
		if (!vis[b[i]]) {
          	// 从 b[i] 往上枚举，把这些点都选上
			int cur = b[i]; 
			while (!vis[cur]) {
              	// 更新 tot
				tot.div(dp[cur] + 1);
				tot.mul(dp[cur]);

				vis[cur] = 1;
				cur = par[cur];
			}
		}
		ans = (ans + tot.get()) % mod;
	}
	cout << ans << endl;
	return;
}
